from solution import retry

calls = {"n": 0}

def test_retries_then_succeeds():
    calls["n"] = 0
    @retry(times=3)
    def flaky():
        calls["n"] += 1
        if calls["n"] < 3:
            raise ValueError("boom")
        return "ok"
    assert flaky() == "ok"
    assert calls["n"] == 3

def test_reraises_after_exhaustion():
    @retry(times=1)
    def always_fails():
        raise RuntimeError("nope")
    import pytest
    with pytest.raises(RuntimeError):
        always_fails()

