// src/api/client.ts
import axios from 'axios';

const http = axios.create({ baseURL: import.meta.env.VITE_API_URL, timeout: 10_000 });


export interface Report {
  id: string;
  title: string;
  status: 'active' | 'archived';
  updatedAt: string;
}

export async function listReports(params: Record<string, string> = {}): Promise<Report[]> {
  const res = await http.get('/reports', { params });
  return res.data.items;
}

export async function updateReport(id: string, patch: Partial<Report>): Promise<Report> {
  const res = await http.patch(`/reports/${id}`, patch);
  return res.data;
}


export interface Widget {
  id: string;
  title: string;
  status: 'active' | 'archived';
  updatedAt: string;
}

export async function listWidgets(params: Record<string, string> = {}): Promise<Widget[]> {
  const res = await http.get('/widgets', { params });
  return res.data.items;
}

export async function updateWidget(id: string, patch: Partial<Widget>): Promise<Widget> {
  const res = await http.patch(`/widgets/${id}`, patch);
  return res.data;
}

