const http = axios.create({ baseURL: import.meta.env.VITE_API_URL, timeout: 10_000 });


export interface Cart {
  id: string;
  title: string;
  status: 'active' | 'archived';
  updatedAt: string;
}

export async function listCarts(params: Record<string, string> = {}): Promise<Cart[]> {
  const res = await http.get('/carts', { params });
  return res.data.items;
}

export async function updateCart(id: string, patch: Partial<Cart>): Promise<Cart> {
  const res = await http.patch(`/carts/${id}`, patch);
  return res.data;
}


export interface Order {
  id: string;
  title: string;
  status: 'active' | 'archived';
  updatedAt: string;
}

export async function listOrders(params: Record<string, string> = {}): Promise<Order[]> {
  const res = await http.get('/orders', { params });
  return res.data.items;
}

export async function updateOrder(id: string, patch: Partial<Order>): Promise<Order> {
  const res = await http.patch(`/orders/${id}`, patch);
  return res.data;
}

