import React from 'react';
import { useStore } from '../store';


export function CartPanel({ id }: { id: string }) {
  const data = useStore((s) => s.cartById[id]);
  const refresh = useStore((s) => s.refreshCart);
  if (!data) return <div className="panel panel-empty">No cart selected</div>;
  return (
    <section className="panel">
      <header className="panel-header">
        <h2>{data.title}</h2>
        <button onClick={() => refresh(id)}>Refresh</button>
      </header>
      <dl>
        <dt>Status</dt><dd>{data.status}</dd>
        <dt>Updated</dt><dd>{new Date(data.updatedAt).toLocaleString()}</dd>
      </dl>
    </section>
  );
}

